APPLE.script:
const fontName = 'Apple Color Emoji';
let isLoaded = document.fonts.check('12px "' + fontName + '"');
const modal = document.createElement('div');
modal.className = 'modal-overlay active';
modal.style.zIndex = '9999';
if (isLoaded) {
    modal.innerHTML = `
        <div class="modal-card">
            <h2 class="modal-title">🍎 Apple Emoji Font</h2>
            <p class="modal-text" style="font-size: 15px; color: #4ade80;">✅ Font is already installed and loaded.</p>
            <button class="btn" id="closeAppleBtn" style="background: transparent; border: 1px solid #4ade80; color: #4ade80;">Awesome</button>
        </div>
    `;
    document.body.appendChild(modal);
    document.getElementById('closeAppleBtn').onclick = () => modal.remove();
} else {
    modal.innerHTML = `
        <div class="modal-card">
            <h2 class="modal-title">🍎 Apple Emoji Font</h2>
            <p class="modal-text" id="dlStatus" style="font-size: 15px; color: #f1c40f;">Initiating System Download...</p>
            <div style="width: 100%; height: 12px; background: rgba(255,255,255,0.1); border-radius: 6px; overflow: hidden; margin-bottom: 10px; border: 1px solid rgba(255,255,255,0.2);">
                <div id="dlBar" style="width: 0%; height: 100%; background: #4ade80; transition: width 0.3s;"></div>
            </div>
            <p id="dlPerc" style="font-size: 12px; color: #aaa; margin-top: 0; margin-bottom: 20px;">Connecting to GitHub...</p>
            <button class="btn" id="closeAppleBtn" style="background: transparent; border: 1px solid rgba(255,255,255,0.2); color: #fff;" disabled>Downloading...</button>
        </div>
    `;
    document.body.appendChild(modal);
    const btn = document.getElementById('closeAppleBtn');
    const bar = document.getElementById('dlBar');
    const perc = document.getElementById('dlPerc');
    const status = document.getElementById('dlStatus');
    btn.onclick = () => modal.remove();

    let progress = 0;
    let dlInterval = setInterval(() => {
        progress += Math.floor(Math.random() * 20) + 5;
        if (progress > 100) progress = 100;

        bar.style.width = progress + '%';
        perc.innerText = progress + '% (Fetching 43.5MB TTF...)';

        if (progress === 100) {
            clearInterval(dlInterval);
            status.innerText = "Applying Font to System...";
            status.style.color = "#4ade80";

            const newStyle = document.createElement('style');
            newStyle.textContent = "@font-face { font-family: 'Apple Color Emoji'; src: url('https://github.com/GORAlexComp/AppleColorEmojiFont/releases/download/v1/AppleColorEmoji.ttf') format('truetype'); }";
            document.head.appendChild(newStyle);

            setTimeout(() => {
                status.innerText = "✅ Font Configured!";
                perc.innerText = "System UI updated. (Browser may take a moment to render)";
                btn.disabled = false;
                btn.innerText = "Close";
                btn.style.borderColor = "#4ade80";
                btn.style.color = "#4ade80";
            }, 1500);
        }
    }, 400);
}
